const isNeighbor = (cell: Cell, other: Cell): boolean => {
  const dx = Math.abs(cell[0] - other[0]);
  const dy = Math.abs(cell[1] - other[1]);
  const isSameCell = dx === 0 && dy === 0;
  return !isSameCell && dx <= 1 && dy <= 1;
};

